1	//! WASM bindings for the COR24 CPU simulator
2	//!
3	//! This module provides JavaScript-accessible interfaces to the CPU.
4	//! WasmCpu wraps EmulatorCore for consistent behavior with the CLI.
5	
6	use crate::assembler::{Assembler, AssemblyResult};
7	use crate::challenge::get_challenges;
8	use crate::cpu::{CpuState, ExecuteResult, Executor};
9	use crate::emulator::EmulatorCore;
10	use wasm_bindgen::prelude::*;
11	use web_sys::console;
12	
13	/// WASM-accessible CPU wrapper backed by EmulatorCore
14	#[wasm_bindgen]
15	#[derive(Clone)]
16	pub struct WasmCpu {
17	    emu: EmulatorCore,
18	    last_result: Option<AssemblyResult>,
19	}
20	
21	impl Default for WasmCpu {
22	    fn default() -> Self {
23	        Self::new()
24	    }
25	}
26	
27	#[wasm_bindgen]
28	impl WasmCpu {
29	    /// Create a new CPU
30	    #[wasm_bindgen(constructor)]
31	    pub fn new() -> Self {
32	        console_error_panic_hook::set_once();
33	        let mut emu = EmulatorCore::new();
34	        emu.set_uart_tx_busy_cycles(0); // instant TX in WASM — no busy-wait needed
35	        Self {
36	            emu,
37	            last_result: None,
38	        }
39	    }
40	
41	    /// Reset the CPU to initial state (preserves memory)
42	    pub fn reset(&mut self) {
43	        self.emu.reset();
44	        self.emu.set_uart_tx_busy_cycles(0);
45	    }
46	
47	    /// Hard reset - clears memory too
48	    pub fn hard_reset(&mut self) {
49	        self.emu.hard_reset();
50	        self.emu.set_uart_tx_busy_cycles(0);
51	        self.last_result = None;
52	    }
53	
54	    /// Assemble source code and load into memory
55	    pub fn assemble(&mut self, source: &str) -> Result<JsValue, JsValue> {
56	        let mut assembler = Assembler::new();
57	        let result = assembler.assemble(source);
58	
59	        if result.errors.is_empty() {
60	            self.emu.hard_reset();
61	            // Load bytes at their correct addresses, tracking program extent
62	            let mut highest_addr: u32 = 0;
63	            for line in &result.lines {
64	                for (i, &b) in line.bytes.iter().enumerate() {
65	                    let addr = line.address + i as u32;
66	                    self.emu.write_byte(addr, b);
67	                    if addr + 1 > highest_addr {
68	                        highest_addr = addr + 1;
69	                    }
70	                }
71	            }
72	            // Use load_program with empty slice to set program_end correctly
73	            self.emu.load_program_extent(highest_addr);
74	
75	            console::log_1(&JsValue::from_str(&format!(
76	                "Loaded {} bytes into memory",
77	                result.bytes.len()
78	            )));
79	
80	            self.last_result = Some(result.clone());
81	            serde_wasm_bindgen::to_value(&result).map_err(|e| JsValue::from_str(&e.to_string()))
82	        } else {
83	            Err(JsValue::from_str(&result.errors.join("\n")))
84	        }
85	    }
86	
87	    /// Get the assembled lines for display
88	    pub fn get_assembled_lines(&self) -> Vec<String> {
89	        if let Some(result) = &self.last_result {
90	            result
91	                .lines
92	                .iter()
93	                .map(|line| {
94	                    if line.bytes.is_empty() {
95	                        format!("       {}", line.source)
96	                    } else {
97	                        let bytes_str: String = line
98	                            .bytes
99	                            .iter()
100	                            .map(|b| format!("{:02X}", b))
101	                            .collect::<Vec<_>>()
102	                            .join(" ");
103	                        format!("{:04X}: {:12} {}", line.address, bytes_str, line.source)
104	                    }
105	                })
106	                .collect()
107	        } else {
108	            Vec::new()
109	        }
110	    }
111	
112	    /// Execute one instruction
113	    pub fn step(&mut self) -> Result<bool, JsValue> {
114	        let result = self.emu.step();
115	        match result.reason {
116	            crate::emulator::StopReason::CycleLimit => Ok(true),
117	            crate::emulator::StopReason::Halted => Ok(false),
118	            crate::emulator::StopReason::InvalidInstruction(byte) => Err(JsValue::from_str(
119	                &format!("Invalid instruction: 0x{:02X}", byte),
120	            )),
121	            _ => Ok(true),
122	        }
123	    }
124	
125	    /// Run a batch of instructions (for animated execution)
126	    pub fn run_batch(&mut self, max_instructions: u32) -> bool {
127	        self.emu.resume();
128	        let result = self.emu.run_batch(max_instructions as u64);
129	        !matches!(
130	            result.reason,
131	            crate::emulator::StopReason::Halted
132	                | crate::emulator::StopReason::InvalidInstruction(_)
133	        )
134	    }
135	
136	    /// Run until halt or error
137	    pub fn run(&mut self) -> Result<(), JsValue> {
138	        self.emu.resume();
139	        let result = self.emu.run_batch(100_000);
140	        match result.reason {
141	            crate::emulator::StopReason::CycleLimit
142	            | crate::emulator::StopReason::Halted
143	            | crate::emulator::StopReason::Paused
144	            | crate::emulator::StopReason::Breakpoint(_) => Ok(()),
145	            crate::emulator::StopReason::InvalidInstruction(byte) => Err(JsValue::from_str(
146	                &format!("Invalid instruction: 0x{:02X}", byte),
147	            )),
148	        }
149	    }
150	
151	    /// Check if CPU is halted
152	    pub fn is_halted(&self) -> bool {
153	        self.emu.is_halted()
154	    }
155	
156	    /// Get program counter
157	    pub fn pc(&self) -> u32 {
158	        self.emu.pc()
159	    }
160	
161	    /// Get instruction count
162	    pub fn instruction_count(&self) -> u64 {
163	        self.emu.instructions_count()
164	    }
165	
166	    /// Get condition flag
167	    pub fn get_c_flag(&self) -> bool {
168	        self.emu.condition_flag()
169	    }
170	
171	    /// Read a register value
172	    pub fn read_register(&self, reg: u8) -> u32 {
173	        self.emu.get_reg(reg)
174	    }
175	
176	    /// Get all register values as an array
177	    pub fn get_registers(&self) -> Vec<u32> {
178	        (0..8).map(|i| self.emu.get_reg(i)).collect()
179	    }
180	
181	    /// Read memory byte
182	    pub fn read_memory(&self, addr: u32) -> u8 {
183	        self.emu.read_byte(addr)
184	    }
185	
186	    /// Get memory slice as bytes
187	    pub fn get_memory_slice(&self, start: u32, len: u32) -> Vec<u8> {
188	        self.emu.read_memory(start, len)
189	    }
190	
191	    // ===== I/O Peripheral Access =====
192	
193	    /// Get LED register value (active-low: bit 0 = 0 means ON)
194	    pub fn get_leds(&self) -> u8 {
195	        self.emu.get_led()
196	    }
197	
198	    /// Check if LED D2 is visually on (active-low)
199	    pub fn is_led_on(&self) -> bool {
200	        self.emu.is_led_on()
201	    }
202	
203	    /// Get switch state (8 bits)
204	    pub fn get_switches(&self) -> u8 {
205	        if self.emu.is_button_pressed() { 0xFE } else { 0xFF }
206	    }
207	
208	    /// Set switch state (simulates external switch input)
209	    pub fn set_switches(&mut self, value: u8) {
210	        self.emu.set_button_pressed(value & 1 == 1);
211	    }
212	
213	    /// Toggle a specific switch bit
214	    pub fn toggle_switch(&mut self, bit: u8) {
215	        if bit == 0 {
216	            let pressed = self.emu.is_button_pressed();
217	            self.emu.set_button_pressed(!pressed);
218	        }
219	    }
220	
221	    /// Get UART output buffer
222	    pub fn get_uart_output(&self) -> String {
223	        self.emu.get_uart_output().to_string()
224	    }
225	
226	    /// Clear UART output buffer
227	    pub fn clear_uart_output(&mut self) {
228	        self.emu.clear_uart_output();
229	    }
230	
231	    /// Send a character to UART RX (simulates input)
232	    pub fn uart_send_char(&mut self, c: char) {
233	        self.emu.send_uart_byte(c as u8);
234	    }
235	
236	    // ===== Additional accessors =====
237	
238	    /// Get program counter (alias for pc())
239	    pub fn get_pc(&self) -> u32 {
240	        self.emu.pc()
241	    }
242	
243	    /// Get condition flag (alias for get_c_flag())
244	    pub fn get_condition_flag(&self) -> bool {
245	        self.emu.condition_flag()
246	    }
247	
248	    /// Get LED value (alias for get_leds())
249	    pub fn get_led_value(&self) -> u8 {
250	        self.emu.get_led()
251	    }
252	
253	    /// Get instruction count as u32 (truncated from u64)
254	    pub fn get_instruction_count(&self) -> u32 {
255	        self.emu.instructions_count() as u32
256	    }
257	
258	    /// Read a byte from memory (alias for read_memory())
259	    pub fn read_byte(&self, addr: u32) -> u8 {
260	        self.emu.read_byte(addr)
261	    }
262	
263	    /// Get the current instruction disassembly (uses EmulatorCore's disassembler)
264	    pub fn get_current_instruction(&self) -> String {
265	        if self.emu.is_halted() {
266	            return "HALTED".to_string();
267	        }
268	        let pc = self.emu.pc();
269	        let (text, _) = self.emu.disassemble_at(pc);
270	        format!("{:04X}: {}", pc, text)
271	    }
272	
273	    /// Get the last N trace entries as formatted strings
274	    pub fn get_trace_lines(&self, n: usize) -> Vec<String> {
275	        self.emu
276	            .trace()
277	            .last_n(n)
278	            .iter()
279	            .map(|e| format!("{}", e))
280	            .collect()
281	    }
282	
283	    /// Get the end address of loaded program (highest address written)
284	    pub fn get_program_end(&self) -> u32 {
285	        self.emu.program_end()
286	    }
287	
288	    /// Check if should stop for LED output (for animation purposes)
289	    pub fn should_stop_for_led(&self) -> bool {
290	        self.emu.cycles() >= 10000
291	    }
292	}
293	
294	// ===== Sparse Memory Access (Rust-only, not wasm_bindgen) =====
295	
296	impl WasmCpu {
297	    /// Get sparse SRAM representation: full 1MB region, only non-zero 16-byte rows included.
298	    pub fn get_sparse_sram(&self) -> components::SparseMemory {
299	        components::SparseMemory::from_slice(self.emu.sram(), 0x000000)
300	    }
301	
302	    /// Get sparse EBR/Stack representation: 0xFEE000–0xFEEC00 (3 KB usable stack area).
303	    pub fn get_sparse_ebr(&self) -> components::SparseMemory {
304	        let ebr = self.emu.ebr();
305	        // EBR is mapped at 0xFEE000. Stack area is 0xFEE000–0xFEEC00 (3072 bytes).
306	        let stack_size = 0xC00.min(ebr.len()); // 3 KB
307	        components::SparseMemory::from_slice(&ebr[..stack_size], 0xFEE000)
308	    }
309	}
310	
311	// ===== Challenge System =====
312	
313	/// Get number of available challenges
314	#[wasm_bindgen]
315	pub fn get_challenge_count() -> usize {
316	    get_challenges().len()
317	}
318	
319	/// Validate a solution for a challenge
320	#[wasm_bindgen]
321	pub fn validate_challenge(challenge_id: usize, source: &str) -> Result<bool, JsValue> {
322	    let challenges = get_challenges();
323	    let challenge = challenges
324	        .iter()
325	        .find(|c| c.id == challenge_id)
326	        .ok_or_else(|| JsValue::from_str(&format!("Challenge {} not found", challenge_id)))?;
327	
328	    let mut assembler = Assembler::new();
329	    let result = assembler.assemble(source);
330	
331	    if !result.errors.is_empty() {
332	        return Err(JsValue::from_str(&result.errors.join("\n")));
333	    }
334	
335	    let mut cpu = CpuState::new();
336	    cpu.load_program(0, &result.bytes);
337	
338	    let executor = Executor::new();
339	    match executor.run(&mut cpu, 100000) {
340	        ExecuteResult::Ok | ExecuteResult::Halted => Ok((challenge.validator)(&cpu)),
341	        ExecuteResult::InvalidInstruction(byte) => Err(JsValue::from_str(&format!(
342	            "Invalid instruction: 0x{:02X}",
343	            byte
344	        ))),
345	        ExecuteResult::MemoryError(addr) => Err(JsValue::from_str(&format!(
346	            "Memory error at address: 0x{:06X}",
347	            addr
348	        ))),
349	    }
350	}
351	
352	/// Run self-tests on all assembler examples.
353	/// If inject_failure is true, forces the first passing test to fail (test-the-test).
354	#[wasm_bindgen]
355	pub fn run_self_tests(inject_failure: bool) -> String {
356	    let results = crate::challenge::run_self_tests(inject_failure);
357	    let json: Vec<String> = results
358	        .iter()
359	        .map(|r| {
360	            format!(
361	                r#"{{"name":"{}","pass":{},"detail":"{}"}}"#,
362	                r.name,
363	                r.pass,
364	                r.detail.replace('"', "'")
365	            )
366	        })
367	        .collect();
368	    format!("[{}]", json.join(","))
369	}
370	
371	/// Initialize the WASM module and mount Yew app
372	#[wasm_bindgen(start)]
373	pub fn init() {
374	    console_error_panic_hook::set_once();
375	    yew::Renderer::<crate::app::App>::new().render();
376	}
377

