                format!("{}", expect_halt),
                format!("{}", cpu.halted),
                cpu.halted == expect_halt,
            ));
            checks.push((
                "mem[256]",
                format!("{}", expect_val),
                format!("{}", val),
                val == expect_val,
            ));
