            let expect_r0: u32 = if inject_bad { 999 } else { 33 };
            checks.push((
                "halted",
                format!("{}", expect_halt),
                format!("{}", cpu.halted),
                cpu.halted == expect_halt,
            ));
            checks.push((
                "r0",
                format!("{}", expect_r0),
                format!("{}", r0),
