                expected.to_string(),
                actual1.clone(),
                actual1 == expected,
            ));
            checks.push((
                "mem[512]",
                expected.to_string(),
                actual2.clone(),
                actual2 == expected,
            ));
        }
        _ => {
            checks.push(("defined", "true".into(), "false".into(), false));
        }
    }

    let pass = checks.iter().all(|c| c.3);
    let detail = checks
